4	/**
5	 * Convert an ImageModelV3File to a URL or data URI string.
6	 *
7	 * If the file is a URL, it returns the URL as-is.
8	 * If the file is base64 data, it returns a data URI with the base64 data.
9	 * If the file is a Uint8Array, it converts it to base64 and returns a data URI.
10	 */
11	export function convertImageModelFileToDataUri(file: ImageModelV3File): string {
12	  if (file.type === 'url') return file.url;
13	
14	  return `data:${file.mediaType};base64,${
15	    typeof file.data === 'string'
16	      ? file.data
17	      : convertUint8ArrayToBase64(file.data)
18	  }`;
19	}
